3_real_world_example.code:
class Article {
  constructor(title, date) {
    this.title = title;
    this.date = date;
  }

  // Static method: Belongs to the class, not the articles
  static compareDates(articleA, articleB) {
    return articleA.date - articleB.date;
  }
}

const a1 = new Article('Intro', new Date(2020, 1, 1));
const a2 = new Article('Advanced', new Date(2021, 1, 1));

//  Fails! Instances don't have static methods
// a1.compareDates(a1, a2); 

//  Works! Call it on the Class itself
Article.compareDates(a1, a2);

